			if(a[i]==a[j])
			{
				dp[i][j]=min(dp[i+1][j],dp[i][j-1]);
			}
			rep(i,j-1,k)
			{
				dp[i][j]=min(dp[i][j],dp[i][k]+dp[k+1][j]);
			}
		}
	}
	printf("%d",dp[1][n]);
}
